  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { bindActionCreators } from 'redux';
  4	import { KialiDispatch } from 'types/Redux';
  5	import { KialiAppState } from 'store/Store';
  6	import { replayQueryTimeSelector, durationSelector } from 'store/Selectors';
  7	import { Tooltip, ButtonVariant, Button, Text } from '@patternfly/react-core';
  8	import { DurationInSeconds, IntervalInMilliseconds, TimeInMilliseconds } from 'types/Common';
  9	import { ToolbarDropdown } from 'components/Dropdown/ToolbarDropdown';
 10	import { UserSettingsActions } from 'actions/UserSettingsActions';
 11	import { Slider } from 'components/IstioWizards/Slider/Slider';
 12	import { KialiIcon } from 'config/KialiIcon';
 13	import { kialiStyle } from 'styles/StyleUtils';
 14	import { toString } from './Utils';
 15	import { serverConfig } from 'config';
 16	import { PFColors } from 'components/Pf/PfColors';
 17	import { DateTimePicker } from './DateTimePicker';
 18	import _ from 'lodash';
 19	import { HistoryManager, URLParam, location } from 'app/History';
 20	
 21	type ReduxStateProps = {
 22	  duration: DurationInSeconds;
 23	  replayQueryTime: TimeInMilliseconds;
 24	};
 25	
 26	type ReduxDispatchProps = {
 27	  setReplayQueryTime: (replayQueryTime: TimeInMilliseconds) => void;
 28	  toggleReplayActive: () => void;
 29	};
 30	
 31	type ReplayProps = ReduxStateProps &
 32	  ReduxDispatchProps & {
 33	    id: string;
 34	  };
 35	
 36	type ReplayWindow = {
 37	  interval: IntervalInMilliseconds;
 38	  startTime: TimeInMilliseconds;
 39	};
 40	
 41	type ReplayStatus = 'initialized' | 'playing' | 'paused' | 'done';
 42	
 43	type ReplayState = {
 44	  isCustomStartTime: boolean;
 45	  refresherRef?: number;
 46	  replayFrame: number;
 47	  replayFrameCount: number;
 48	  replaySpeed: IntervalInMilliseconds;
 49	  replayWindow: ReplayWindow;
 50	  status: ReplayStatus;
 51	};
 52	
 53	type ReplaySpeed = {
 54	  speed: IntervalInMilliseconds;
 55	  text: string;
 56	};
 57	
 58	export const replayBorder = kialiStyle({
 59	  borderLeft: `solid 0.25rem ${PFColors.Replay}`
 60	});
 61	
 62	/**
 63	 * Overrides for Replay use of the Slider component.
 64	 * - to avoid the tt occluding other components (like close replay), limit to when mouse is over the slider only,
 65	 * not the tooltip area itself.
 66	 * - to avoid the tooltip getting clipped on the right, add padding to move the shift the "attach" point
 67	 */
 68	const replaySliderStyle = kialiStyle({
 69	  $nest: {
 70	    '& .slider': {
 71	      $nest: {
 72	        '& .slider-selection.tick-slider-selection': {
 73	          background: 'var(--pf-t--global--color--brand--default)' // should match PFColors.Replay
 74	        },
 75	
 76	        '& .tooltip': {
 77	          pointerEvents: 'none',
 78	          paddingRight: '175px'
 79	        }
 80	      }
 81	    }
 82	  }
 83	});
 84	
 85	// key represents replay interval in milliseconds
 86	const replayIntervals = {
 87	  60000: '1 minute',
 88	  300000: '5 minutes',
 89	  600000: '10 minutes',
 90	  1800000: '30 minutes'
 91	};
 92	
 93	const replayLastIntervals = _.mapValues(replayIntervals, i => `Last ${i}`);
 94	
 95	// key represents speed in milliseconds (i.e. how long to wait before refreshing-the-frame (fetching new data)
 96	const replaySpeeds: ReplaySpeed[] = [
 97	  { speed: 5000, text: 'slow' },
 98	  { speed: 3000, text: 'medium' },
 99	  { speed: 1000, text: 'fast' }
100	];
101	
102	const defaultReplayInterval: IntervalInMilliseconds = 300000; // 5 minutes
103	const defaultReplaySpeed: IntervalInMilliseconds = 3000; // medium
104	const frameInterval: IntervalInMilliseconds = 10000; // clock advances 10s per frame
105	
106	const controlStyle = kialiStyle({
107	  display: 'flex',
108	  alignItems: 'center',
109	  marginBottom: '0.25rem'
110	});
111	
112	const controlButtonStyle = kialiStyle({
113	  marginLeft: '33%',
114	  paddingRight: '0.5rem',
115	  height: '2rem'
116	});
117	
118	const controlIconStyle = kialiStyle({
119	  fontSize: '1.5em'
120	});
121	
122	const frameStyle = kialiStyle({
123	  marginRight: '1.25rem'
124	});
125	
126	const isCustomStyle = kialiStyle({
127	  height: '2.25rem'
128	});
129	
130	const isCustomActiveStyle = kialiStyle({
131	  color: PFColors.Active
132	});
133	
134	const replayStyle = kialiStyle({
135	  display: 'flex',
136	  width: '100%',
137	  padding: '0 0.25rem 0 0.5rem'
138	});
139	
140	const sliderStyle = kialiStyle({
141	  width: '100%',
142	  margin: '0 -0.5rem 0 1.25rem'
143	});
144	
145	const speedStyle = kialiStyle({
146	  paddingLeft: '0.5rem',
147	  paddingRight: '0.5rem'
148	});
149	
150	const speedActiveStyle = kialiStyle({
151	  color: PFColors.Active,
152	  fontWeight: 'bolder'
153	});
154	
155	const vrStyle = kialiStyle({
156	  border: '1px inset',
157	  height: '1.25rem',
158	  marginTop: '0.25rem'
159	});
160	
161	class ReplayComponent extends React.PureComponent<ReplayProps, ReplayState> {
162	  static getFrameCount = (elapsedTime: IntervalInMilliseconds): number => {
163	    return elapsedTime > 0 ? Math.floor(elapsedTime / frameInterval) : 0;
164	  };
165	
166	  static queryTimeToFrame = (replayQueryTime: TimeInMilliseconds, replayStartTime: TimeInMilliseconds): number => {
167	    const elapsedTime: IntervalInMilliseconds = replayQueryTime - replayStartTime;
168	    const frame: number = ReplayComponent.getFrameCount(elapsedTime);
169	    return frame;
170	  };
171	
172	  static frameToQueryTime = (frame: number, replayWindow: ReplayWindow): TimeInMilliseconds => {
173	    return replayWindow.startTime + frame * frameInterval;
174	  };
175	
176	  constructor(props: ReplayProps) {
177	    super(props);
178	
179	    // Let URL set initial state at construction time.
180	    // Note, URLParam.GRAPH_REPLAY_START is only set for custom start times
181	    let interval = defaultReplayInterval;
182	    const urlParams = new URLSearchParams(location.getSearch());
183	    const urlReplayInterval = HistoryManager.getParam(URLParam.GRAPH_REPLAY_INTERVAL, urlParams);
184	
185	    if (!!urlReplayInterval) {
186	      interval = Number(urlReplayInterval);
187	    }
188	
189	    let startTime = new Date().getTime() - interval;
190	    let isCustomStartTime = false;
191	    const urlReplayStart = HistoryManager.getParam(URLParam.GRAPH_REPLAY_START, urlParams);
192	
193	    if (!!urlReplayStart) {
194	      startTime = Number(urlReplayStart);
195	      isCustomStartTime = true;
196	    }
197	
198	    this.state = {
199	      isCustomStartTime: isCustomStartTime,
200	      refresherRef: undefined,
201	      replayFrame: ReplayComponent.queryTimeToFrame(0, startTime),
202	      replayFrameCount: ReplayComponent.getFrameCount(interval),
203	      replaySpeed: defaultReplaySpeed,
204	      replayWindow: { interval: interval, startTime: startTime } as ReplayWindow,
205	      status: 'initialized'
206	    };
207	  }
208	
209	  componentDidUpdate(_prevProps: ReplayProps, prevState: ReplayState): void {
210	    const isCustomStartChange = this.state.isCustomStartTime !== prevState.isCustomStartTime;
211	    const isIntervalChange = this.state.replayWindow.interval !== prevState.replayWindow.interval;
212	
213	    if (isCustomStartChange || isIntervalChange) {
214	      this.initReplay();
215	      return;
216	    }
217	
218	    let refresherChange = this.state.status !== prevState.status;
219	    refresherChange = refresherChange || this.state.replaySpeed !== prevState.replaySpeed;
220	
221	    if (refresherChange) {
222	      this.updateRefresher();
223	    }
224	
225	    if (this.state.status !== 'initialized') {
226	      const frameQueryTime = ReplayComponent.frameToQueryTime(this.state.replayFrame, this.state.replayWindow);
227	      if (frameQueryTime !== this.props.replayQueryTime) {
228	        this.props.setReplayQueryTime(frameQueryTime);
229	      }
230	    }
231	  }
232	
233	  componentWillUnmount(): void {
234	    HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_INTERVAL);
235	    HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_START);
236	
237	    if (this.state.refresherRef) {
238	      clearInterval(this.state.refresherRef);
239	    }
240	  }
241	
242	  render(): React.ReactNode {
243	    if (!this.state.replayWindow.startTime) {
244	      return null;
245	    }
246	
247	    const selectedTime: Date = new Date(this.state.replayWindow.startTime);
248	    const endTime: TimeInMilliseconds = selectedTime.getTime() + this.state.replayWindow.interval;
249	    const endString = toString(endTime, { month: undefined, day: undefined, second: '2-digit' });
250	    const ticks: number[] = Array.from(Array(this.state.replayFrameCount).keys());
251	    const now = Date.now();
252	    const maxTime: Date = new Date(now - this.state.replayWindow.interval);
253	    const minTime: Date = new Date(
254	      now - (serverConfig.prometheus.storageTsdbRetention! * 1000 + this.state.replayWindow.interval)
255	    );
256	
257	    const dropdownOptions = this.state.isCustomStartTime ? replayIntervals : replayLastIntervals;
258	
259	    return (
260	      <div className={`${replayStyle} ${replayBorder}`}>
261	        {this.state.isCustomStartTime && (
262	          <Tooltip content="Replay start time">
263	            <DateTimePicker
264	              injectTimes={[maxTime]}
265	              maxDate={maxTime}
266	              minDate={minTime}
267	              onChange={(date: Date) => this.onPickerChange(date)}
268	              selected={selectedTime}
269	            />
270	          </Tooltip>
271	        )}
272	
273	        <ToolbarDropdown
274	          id="replay-interval"
275	          className={isCustomStyle}
276	          handleSelect={key => this.setReplayInterval(Number(key))}
277	          value={String(this.state.replayWindow.interval)}
278	          label={dropdownOptions[this.state.replayWindow.interval]}
279	          options={dropdownOptions}
280	          tooltip="Replay length"
281	        />
282	
283	        <Tooltip
284	          key="toggle-is-custom"
285	          position="top"
286	          content={`Set ${this.state.isCustomStartTime ? 'simple' : 'custom'} start time`}
287	        >
288	          <Button className={isCustomStyle} variant={ButtonVariant.control} onClick={this.toggleCustomStartTime}>
289	            <KialiIcon.UserClock className={this.state.isCustomStartTime ? isCustomActiveStyle : ''} />
290	          </Button>
291	        </Tooltip>
292	
293	        <span className={sliderStyle}>
294	          <div className={replaySliderStyle}>
295	            <Slider
296	              key={endString} // on new endTime force new slider because of bug updating tick labels
297	              id="replay-slider"
298	              orientation="horizontal"
299	              min={0}
300	              max={this.state.replayFrameCount}
301	              maxLimit={this.state.replayFrameCount}
302	              step={1}
303	              value={this.state.replayFrame}
304	              ticks={ticks}
305	              tooltip={true}
306	              tooltipFormatter={this.formatTooltip}
307	              onSlideStop={this.setReplayFrame}
308	              input={false}
309	              locked={false}
310	              showLock={false}
311	              mirrored={false}
312	              showMirror={false}
313	            />
314	          </div>
315	
316	          <span className={controlStyle}>
317	            {this.state.status === 'playing' ? (
318	              <Tooltip key="replay-pause" position="top" content="Pause" entryDelay={1000}>
319	                <Button
320	                  data-test="graph-replay-pause-button"
321	                  className={controlButtonStyle}
322	                  variant={ButtonVariant.link}
323	                  onClick={this.pause}
324	                >
325	                  <KialiIcon.PauseCircle className={controlIconStyle} />
326	                </Button>
327	              </Tooltip>
328	            ) : (
329	              <Tooltip
330	                key="replay-play"
331	                position="top"
332	                content={this.state.status === 'done' ? 'Play again' : 'Play'}
333	                entryDelay={1000}
334	              >
335	                <Button
336	                  data-test="graph-replay-play-button"
337	                  className={controlButtonStyle}
338	                  variant={ButtonVariant.link}
339	                  onClick={this.play}
340	                >
341	                  <KialiIcon.PlayCircle className={controlIconStyle} />
342	                </Button>
343	              </Tooltip>
344	            )}
345	
346	            <Text className={frameStyle}>{this.formatFrame(this.state.replayFrame)}</Text>
347	
348	            {replaySpeeds.map((s, i, a) => this.speedButton(s, i === a.length - 1))}
349	          </span>
350	        </span>
351	      </div>
352	    );
353	  }
354	
355	  formatTooltip = (val: number): string => {
356	    const time: string = toString(ReplayComponent.frameToQueryTime(val, this.state.replayWindow), {
357	      second: '2-digit'
358	    });
359	
360	    return `${time} [${val}/${this.state.replayFrameCount}]`;
361	  };
362	
363	  formatFrame = (frame: number): string => {
364	    const elapsedTime: IntervalInMilliseconds = frame * frameInterval;
365	    const elapsedSec: number = Math.floor((elapsedTime / 1000) % 60);
366	    const elapsedMin: number = Math.floor((elapsedTime / 1000 - elapsedSec) / 60);
367	    const zeroPadSec: string = elapsedSec < 10 ? '0' : '';
368	    const zeroPadMin: string = elapsedMin < 10 ? '0' : '';
369	    const elapsed = `${zeroPadMin}${elapsedMin}:${zeroPadSec}${elapsedSec}`;
370	
371	    return elapsed;
372	  };
373	
374	  private toggleCustomStartTime = (): void => {
375	    this.setState({ isCustomStartTime: !this.state.isCustomStartTime });
376	  };
377	
378	  private onPickerChange = (date: Date): void => {
379	    this.setReplayStartTime(date.getTime());
380	  };
381	
382	  private initReplay = (): void => {
383	    const interval: IntervalInMilliseconds = !!this.state.replayWindow.interval
384	      ? this.state.replayWindow.interval
385	      : defaultReplayInterval;
386	
387	    const startTime: TimeInMilliseconds = this.state.isCustomStartTime
388	      ? this.state.replayWindow.startTime
389	      : new Date().getTime() - interval;
390	
391	    this.setState({ status: 'initialized' });
392	    this.setReplayWindow({ interval: interval, startTime: startTime } as ReplayWindow);
393	  };
394	
395	  private setReplayStartTime = (startTime: TimeInMilliseconds): void => {
396	    this.setReplayWindow({ interval: this.state.replayWindow.interval, startTime: startTime });
397	  };
398	
399	  private setReplayInterval = (interval: IntervalInMilliseconds): void => {
400	    this.setReplayWindow({ interval: interval, startTime: this.state.replayWindow.startTime });
401	  };
402	
403	  private setReplayWindow = (replayWindow: ReplayWindow): void => {
404	    // For simplicity/readability, round custom start times to the minute.
405	    if (this.state.isCustomStartTime) {
406	      replayWindow.startTime = new Date(replayWindow.startTime).setSeconds(0, 0);
407	    }
408	
409	    // ensure redux state and URL are aligned
410	    if (replayWindow.interval === defaultReplayInterval) {
411	      HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_INTERVAL);
412	    } else if (replayWindow.interval !== this.state.replayWindow.interval) {
413	      HistoryManager.setParam(URLParam.GRAPH_REPLAY_INTERVAL, String(replayWindow.interval));
414	    }
415	
416	    if (!this.state.isCustomStartTime || !replayWindow.startTime) {
417	      HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_START);
418	    } else if (replayWindow.startTime !== this.state.replayWindow.startTime) {
419	      HistoryManager.setParam(URLParam.GRAPH_REPLAY_START, String(replayWindow.startTime));
420	    }
421	
422	    const frameCount = ReplayComponent.getFrameCount(replayWindow.interval);
423	
424	    this.setState({
425	      replayFrame: 0,
426	      replayFrameCount: frameCount,
427	      replayWindow: replayWindow
428	    });
429	  };
430	
431	  private setReplaySpeed = (replaySpeed: IntervalInMilliseconds): void => {
432	    this.setState({ replaySpeed: replaySpeed });
433	  };
434	
435	  private done = (): void => {
436	    this.setState({ status: 'done' });
437	  };
438	
439	  private pause = (): void => {
440	    this.setState({ status: 'paused' });
441	  };
442	
443	  private play = (): void => {
444	    const atEnd = this.state.replayFrame >= this.state.replayFrameCount;
445	    this.setState({ replayFrame: atEnd ? 0 : this.state.replayFrame, status: 'playing' });
446	  };
447	
448	  private setReplayFrame = (frame: number): void => {
449	    if (frame !== this.state.replayFrame) {
450	      let status: ReplayStatus = this.state.status === 'initialized' ? 'initialized' : 'paused';
451	      status = frame === this.state.replayFrameCount ? 'done' : status;
452	      this.setState({ replayFrame: frame, status: status });
453	    }
454	  };
455	
456	  private updateRefresher = (): void => {
457	    if (this.state.refresherRef) {
458	      clearInterval(this.state.refresherRef);
459	    }
460	    if (this.state.status !== 'playing' || !this.state.replayWindow.interval) {
461	      return;
462	    }
463	
464	    let refresherRef: number | undefined = undefined;
465	    refresherRef = window.setInterval(this.handleRefresh, this.state.replaySpeed);
466	    this.setState({ refresherRef: refresherRef });
467	  };
468	
469	  private handleRefresh = (): void => {
470	    const nextFrame = this.state.replayFrame + 1;
471	
472	    if (nextFrame > this.state.replayFrameCount) {
473	      this.done();
474	    } else {
475	      this.setState({ replayFrame: nextFrame });
476	      this.props.setReplayQueryTime(ReplayComponent.frameToQueryTime(nextFrame, this.state.replayWindow));
477	    }
478	  };
479	
480	  private speedButton = (replaySpeed: ReplaySpeed, isLast: boolean): React.ReactNode => {
481	    const isActive = this.state.replaySpeed === replaySpeed.speed;
482	
483	    return (
484	      <>
485	        <Button
486	          data-test={`speed-${replaySpeed.text}`}
487	          key={`speed-${replaySpeed.text}`}
488	          className={speedStyle}
489	          variant={ButtonVariant.plain}
490	          isActive={isActive}
491	          onClick={() => this.setReplaySpeed(replaySpeed.speed)}
492	        >
493	          <Text className={isActive ? speedActiveStyle : undefined}>{replaySpeed.text}</Text>
494	        </Button>
495	
496	        {!isLast && <div className={vrStyle} />}
497	      </>
498	    );
499	  };
500	}
501	
502	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
503	  duration: durationSelector(state),
504	  replayQueryTime: replayQueryTimeSelector(state)
505	});
506	
507	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => ({
508	  setReplayQueryTime: bindActionCreators(UserSettingsActions.setReplayQueryTime, dispatch),
509	  toggleReplayActive: bindActionCreators(UserSettingsActions.toggleReplayActive, dispatch)
510	});
511	
512	export const Replay = connect(mapStateToProps, mapDispatchToProps)(ReplayComponent);

