365	  formatFrame = (frame: number): string => {
366	    const elapsedTime: IntervalInMilliseconds = frame * frameInterval;
367	    const elapsedSec: number = Math.floor((elapsedTime / 1000) % 60);
368	    const elapsedMin: number = Math.floor((elapsedTime / 1000 - elapsedSec) / 60);
369	    const zeroPadSec: string = elapsedSec < 10 ? '0' : '';
370	    const zeroPadMin: string = elapsedMin < 10 ? '0' : '';
371	    const elapsed = `${zeroPadMin}${elapsedMin}:${zeroPadSec}${elapsedSec}`;
372	
373	    return elapsed;
374	  };
