405	  private setReplayWindow = (replayWindow: ReplayWindow): void => {
406	    // For simplicity/readability, round custom start times to the minute.
407	    if (this.state.isCustomStartTime) {
408	      replayWindow.startTime = new Date(replayWindow.startTime).setSeconds(0, 0);
409	    }
410	
411	    // ensure redux state and URL are aligned
412	    if (replayWindow.interval === defaultReplayInterval) {
413	      HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_INTERVAL);
414	    } else if (replayWindow.interval !== this.state.replayWindow.interval) {
415	      HistoryManager.setParam(URLParam.GRAPH_REPLAY_INTERVAL, String(replayWindow.interval));
416	    }
417	
418	    if (!this.state.isCustomStartTime || !replayWindow.startTime) {
419	      HistoryManager.deleteParam(URLParam.GRAPH_REPLAY_START);
420	    } else if (replayWindow.startTime !== this.state.replayWindow.startTime) {
421	      HistoryManager.setParam(URLParam.GRAPH_REPLAY_START, String(replayWindow.startTime));
422	    }
423	
424	    const frameCount = ReplayComponent.getFrameCount(replayWindow.interval);
425	
426	    this.setState({
427	      replayFrame: 0,
428	      replayFrameCount: frameCount,
429	      replayWindow: replayWindow
430	    });
431	  };
