450	  private setReplayFrame = (frame: number): void => {
451	    if (frame !== this.state.replayFrame) {
452	      let status: ReplayStatus = this.state.status === 'initialized' ? 'initialized' : 'paused';
453	      status = frame === this.state.replayFrameCount ? 'done' : status;
454	      this.setState({ replayFrame: frame, status: status });
