458	  private updateRefresher = (): void => {
459	    if (this.state.refresherRef) {
460	      clearInterval(this.state.refresherRef);
461	    }
462	    if (this.state.status !== 'playing' || !this.state.replayWindow.interval) {
463	      return;
464	    }
465	
466	    let refresherRef: number | undefined = undefined;
467	    refresherRef = window.setInterval(this.handleRefresh, this.state.replaySpeed);
468	    this.setState({ refresherRef: refresherRef });
469	  };
470	
471	  private handleRefresh = (): void => {
472	    const nextFrame = this.state.replayFrame + 1;
473	
474	    if (nextFrame > this.state.replayFrameCount) {
475	      this.done();
476	    } else {
477	      this.setState({ replayFrame: nextFrame });
478	      this.props.setReplayQueryTime(ReplayComponent.frameToQueryTime(nextFrame, this.state.replayWindow));
479	    }
480	  };
